Word Clouds per Country


Code
top_words &lt;- tokens_clean |&gt;
  count(country, word, sort = TRUE) |&gt;
  group_by(country) |&gt;
  slice_max(n, n = 80) |&gt;
  ungroup()

top_words |&gt;
  ggplot(aes(label = word, size = n, color = n)) +
  geom_text_wordcloud(rm_outside = TRUE, seed = 42) +
  scale_size_area(max_size = 10) +
  scale_color_viridis_c(option = "plasma") +
  facet_wrap(~country, ncol = 3) +
  theme_minimal(base_size = 12) +
  theme(strip.text = element_text(face = "bold", size = 13)) +
  labs(title = "Most frequent words per country (native language, stopwords removed)")

TF-IDF: Most Distinctive Words per Country
TF-IDF measures which words are distinctive to each country relative to the full corpus.


Code
tfidf &lt;- tokens_clean |&gt;
  count(country, word, sort = TRUE) |&gt;
  bind_tf_idf(word, country, n) |&gt;
  group_by(country) |&gt;
  slice_max(tf_idf, n = 10) |&gt;
  ungroup()

tfidf |&gt;
  mutate(word = reorder_within(word, tf_idf, country)) |&gt;
  ggplot(aes(x = tf_idf, y = word, fill = country)) +
  geom_col(show.legend = FALSE) +
  facet_wrap(~country, scales = "free_y", ncol = 3) +
  scale_y_reordered() +
  scale_fill_viridis_d(option = "turbo") +
  labs(
    title = "Most distinctive words per country (TF-IDF)",
    subtitle = "Words with high TF-IDF are used much more by this country than others",
    x = "TF-IDF score", y = NULL
  ) +
  theme_minimal(base_size = 11) +
  theme(strip.text = element_text(face = "bold"))

Bigram Analysis


Code
bigrams &lt;- df |&gt;
  select(article_id, country, language, full_text) |&gt;
  unnest_tokens(bigram, full_text, token = "ngrams", n = 2) |&gt;
  separate(bigram, into = c("word1", "word2"), sep = " ") |&gt;
  # Remove bigrams containing stopwords
  anti_join(all_stopwords, by = c("word1" = "word", "language")) |&gt;
  anti_join(all_stopwords, by = c("word2" = "word", "language")) |&gt;
  filter(nchar(word1) &gt; 2, nchar(word2) &gt; 2) |&gt;
  filter(!str_detect(word1, "^\\d+$"), !str_detect(word2, "^\\d+$")) |&gt;
  unite(bigram, word1, word2, sep = " ") |&gt;
  count(country, bigram, sort = TRUE) |&gt;
  group_by(country) |&gt;
  slice_max(n, n = 10) |&gt;
  ungroup()

bigrams |&gt;
  mutate(bigram = reorder_within(bigram, n, country)) |&gt;
  ggplot(aes(x = n, y = bigram, fill = country)) +
  geom_col(show.legend = FALSE) +
  facet_wrap(~country, scales = "free_y", ncol = 3) +
  scale_y_reordered() +
  scale_fill_viridis_d(option = "turbo") +
  labs(
    title = "Most common two-word phrases per country",
    x = "Count", y = NULL
  ) +
  theme_minimal(base_size = 11) +
  theme(strip.text = element_text(face = "bold"))

7-Day Rolling Average by Country


Code
daily &lt;- df |&gt;
  group_by(country, published_date) |&gt;
  summarise(net = mean(bert_net, na.rm = TRUE), .groups = "drop") |&gt;
  arrange(country, published_date) |&gt;
  group_by(country) |&gt;
  mutate(rolling_net = rollmean(net, k = 7, fill = NA, align = "right")) |&gt;
  ungroup()

daily |&gt;
  ggplot(aes(x = published_date, y = rolling_net, color = country)) +
  geom_line(linewidth = 1, na.rm = TRUE) +
  geom_hline(yintercept = 0, linetype = "dashed", color = "grey50") +
  scale_color_viridis_d(option = "turbo", name = "Country") +
  scale_x_date(date_breaks = "2 weeks", date_labels = "%b %d") +
  labs(
    title = "7-day rolling average net sentiment by country",
    x = NULL, y = "Rolling avg net sentiment"
  ) +
  theme_minimal(base_size = 13)
